-- calc_language_candidates_has_grammar
-- Field: LanguageCandidates.HasGrammar
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_language_candidates_has_grammar(p_language_candidate_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((SELECT has_syntax FROM language_candidates WHERE language_candidate_id = p_language_candidate_id) = TRUE)::boolean;
$$ LANGUAGE sql STABLE;

-- calc_language_candidates_question
-- Field: LanguageCandidates.Question
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_language_candidates_question(p_language_candidate_id TEXT)
RETURNS TEXT AS $$
  SELECT ('Is " & (SELECT NULLIF(name, '''') FROM language_candidates WHERE language_candidate_id = p_language_candidate_id) & " a language?')::text;
$$ LANGUAGE sql STABLE;

-- calc_language_candidates_predicted_answer
-- Field: LanguageCandidates.PredictedAnswer
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_language_candidates_predicted_answer(p_language_candidate_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((COALESCE((SELECT has_syntax FROM language_candidates WHERE language_candidate_id = p_language_candidate_id), FALSE) AND COALESCE((SELECT is_parsed FROM language_candidates WHERE language_candidate_id = p_language_candidate_id), FALSE) AND calc_language_candidates_is_description_of(p_language_candidate_id) AND COALESCE((SELECT has_linear_decoding_pressure FROM language_candidates WHERE language_candidate_id = p_language_candidate_id), FALSE) AND COALESCE((SELECT resolves_to_an_ast FROM language_candidates WHERE language_candidate_id = p_language_candidate_id), FALSE) AND COALESCE((SELECT is_stable_ontology_reference FROM language_candidates WHERE language_candidate_id = p_language_candidate_id), FALSE) AND NOT (COALESCE((SELECT can_be_held FROM language_candidates WHERE language_candidate_id = p_language_candidate_id), FALSE)) AND NOT (COALESCE((SELECT has_identity FROM language_candidates WHERE language_candidate_id = p_language_candidate_id), FALSE))))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_language_candidates_prediction_predicates
-- Field: LanguageCandidates.PredictionPredicates
-- Type: calculated | DataType: string | Returns: TEXT

CREATE OR REPLACE FUNCTION calc_language_candidates_prediction_predicates(p_language_candidate_id TEXT)
RETURNS TEXT AS $$
  SELECT (CONCAT(CASE WHEN COALESCE((SELECT has_syntax FROM language_candidates WHERE language_candidate_id = p_language_candidate_id), FALSE) THEN ('Has Syntax')::text ELSE ('No Syntax')::text END, ' & ', CASE WHEN COALESCE((SELECT is_parsed FROM language_candidates WHERE language_candidate_id = p_language_candidate_id), FALSE) THEN ('Requires Parsing')::text ELSE ('No Parsing Neede')::text END, ' & ', CASE WHEN calc_language_candidates_is_description_of(p_language_candidate_id) THEN ('Describes the thing')::text ELSE ('Is the Thing')::text END, ' & ', CASE WHEN COALESCE((SELECT has_linear_decoding_pressure FROM language_candidates WHERE language_candidate_id = p_language_candidate_id), FALSE) THEN ('Has Linear Decoding Pressure')::text ELSE ('No Decoding Pressure')::text END, ' & ', CASE WHEN COALESCE((SELECT resolves_to_an_ast FROM language_candidates WHERE language_candidate_id = p_language_candidate_id), FALSE) THEN ('Resolves to AST')::text ELSE ('No AST')::text END, ', ', CASE WHEN COALESCE((SELECT is_stable_ontology_reference FROM language_candidates WHERE language_candidate_id = p_language_candidate_id), FALSE) THEN ('Is Stable Ontology')::text ELSE ('Not ''Ontology''')::text END, ' AND ', CASE WHEN COALESCE((SELECT can_be_held FROM language_candidates WHERE language_candidate_id = p_language_candidate_id), FALSE) THEN ('Can Be Held')::text ELSE ('Can''t Be Held')::text END, ', ', CASE WHEN COALESCE((SELECT has_identity FROM language_candidates WHERE language_candidate_id = p_language_candidate_id), FALSE) THEN ('Has Identity')::text ELSE ('Has no Identity')::text END))::text;
$$ LANGUAGE sql STABLE;

-- calc_language_candidates_prediction_fail
-- Field: LanguageCandidates.PredictionFail
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_language_candidates_prediction_fail(p_language_candidate_id TEXT)
RETURNS TEXT AS $$
  SELECT (CONCAT(CASE WHEN NOT (calc_language_candidates_predicted_answer(p_language_candidate_id) = (SELECT is_language FROM language_candidates WHERE language_candidate_id = p_language_candidate_id)) THEN (CONCAT((SELECT NULLIF(name, '') FROM language_candidates WHERE language_candidate_id = p_language_candidate_id), ' ', CASE WHEN calc_language_candidates_predicted_answer(p_language_candidate_id) THEN ('Is')::text ELSE ('Isn''t')::text END, ' a Family Feud Language, but ', CASE WHEN COALESCE((SELECT is_language FROM language_candidates WHERE language_candidate_id = p_language_candidate_id), FALSE) THEN ('Is')::text ELSE ('Is Not')::text END, ' marked as a ''Language Candidate.'''))::text ELSE ('')::text END, CASE WHEN calc_language_candidates_is_open_closed_world_conflicted(p_language_candidate_id) THEN (' - Open World vs. Closed World Conflict.')::text ELSE ('')::text END))::text;
$$ LANGUAGE sql STABLE;

-- calc_language_candidates_is_description_of
-- Field: LanguageCandidates.IsDescriptionOf
-- Type: calculated | DataType: boolean | Returns: BOOLEAN

CREATE OR REPLACE FUNCTION calc_language_candidates_is_description_of(p_language_candidate_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (((SELECT distance_from_concept FROM language_candidates WHERE language_candidate_id = p_language_candidate_id))::NUMERIC > 1)::boolean;
$$ LANGUAGE sql STABLE;

-- calc_language_candidates_is_open_closed_world_conflicted
-- Field: LanguageCandidates.IsOpenClosedWorldConflicted
-- Type: calculated | DataType: boolean | Returns: BOOLEAN

CREATE OR REPLACE FUNCTION calc_language_candidates_is_open_closed_world_conflicted(p_language_candidate_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((COALESCE((SELECT is_open_world FROM language_candidates WHERE language_candidate_id = p_language_candidate_id), FALSE) AND COALESCE((SELECT is_closed_world FROM language_candidates WHERE language_candidate_id = p_language_candidate_id), FALSE)))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_language_candidates_relationship_to_concept
-- Field: LanguageCandidates.RelationshipToConcept
-- Type: calculated | DataType: string | Returns: TEXT

CREATE OR REPLACE FUNCTION calc_language_candidates_relationship_to_concept(p_language_candidate_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN ((SELECT distance_from_concept FROM language_candidates WHERE language_candidate_id = p_language_candidate_id))::NUMERIC = 1 THEN ('IsMirrorOf')::text ELSE ('IsDescriptionOf')::text END)::text;
$$ LANGUAGE sql STABLE;

